class JamRef implements JamVal {
  private JamVal contents;

  public JamRef(JamVal val) { contents = val; }
  public JamVal contents() { return contents; }
  public void setContents(JamVal val) { contents = val; }

  public <ResType> ResType accept(JamValVisitor<ResType> jvv) { return jvv.forJamRef(this); }
  public String toString() { return "(ref " + contents + ")"; }
}

